  <div id="modal_em_detail" class="modal fade"><div class="modal-dialog modal-lg" style="width:92%"><div class="modal-content"><div class="modal-header"><button class="close" data-dismiss="modal">&times;</button><h4 class="modal-title">Employee Detail</h4></div><div class="modal-body" id="em_detail_body"></div><div class="modal-footer"><button class="btn btn-default" data-dismiss="modal"><?=hr_h('common_close', 'Close');?></button></div></div></div></div>
</section>
<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script><script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
<script>
function emError(m){$('.isi_warning_delete').text(m||'Employee gagal diproses.');$('.error_data_delete').fadeIn();}
function emFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),employment_status:$('#filter_employment_status').val(),employee_group:$('#filter_employee_group').val(),department_code:$('#filter_department_code').val(),keyword:$('#filter_keyword').val()};}
function emSet(selector,value,text){var el=$(selector);if(!value){el.val(null).trigger('change');return;}var exists=false;el.find('option').each(function(){if(this.value==value){exists=true;return false;}});if(!exists)el.append(new Option(text||value,value,true,true));el.val(value).trigger('change');}
var emFamilies=[],emEducations=[],emDocuments=[];
function emEsc(v){return $('<div/>').text(v||'').html();}
function emSyncChildJson(){$('#family_rows_json').val(JSON.stringify(emFamilies));$('#education_rows_json').val(JSON.stringify(emEducations));$('#document_rows_json').val(JSON.stringify(emDocuments));$('#family_badge').text(emFamilies.length);$('#education_badge').text(emEducations.length);$('#document_badge').text(emDocuments.length);}
function emRenderChildren(){var h='';emFamilies.forEach(function(r,i){h+='<tr><td>'+emEsc(r.relationship_type)+'</td><td>'+emEsc(r.family_name)+'</td><td>'+emEsc(r.gender)+'</td><td>'+emEsc(r.birth_date)+'</td><td>'+emEsc((r.identity_type||'')+' '+(r.identity_no||''))+'</td><td>'+emEsc(r.phone)+'</td><td>Dependent '+emEsc(r.is_dependent)+' / Emergency '+emEsc(r.emergency_contact)+'</td><td>'+emEsc(r.status)+'</td><td><button type="button" class="btn btn-danger btn-xs btn-del-family" data-i="'+i+'"><i class="fa fa-trash"></i></button></td></tr>';});$('#tbl_family tbody').html(h||'<tr><td colspan="9" class="text-center text-muted">Belum ada family data.</td></tr>');
h='';emEducations.forEach(function(r,i){h+='<tr><td>'+emEsc(r.education_level)+'</td><td>'+emEsc(r.education_type)+'</td><td>'+emEsc(r.institution_name)+'</td><td>'+emEsc(r.major)+'</td><td>'+emEsc(r.graduation_year)+'</td><td>'+emEsc(r.certificate_no)+'</td><td>'+emEsc(r.gpa)+'</td><td>'+emEsc((r.verified_status||'')+' / '+(r.status||''))+'</td><td><button type="button" class="btn btn-danger btn-xs btn-del-education" data-i="'+i+'"><i class="fa fa-trash"></i></button></td></tr>';});$('#tbl_education tbody').html(h||'<tr><td colspan="9" class="text-center text-muted">Belum ada education data.</td></tr>');
h='';emDocuments.forEach(function(r,i){var file=r.file_ref?'<a href="<?=base_url();?>'+emEsc(r.file_ref)+'" target="_blank">'+emEsc(r.file_ref).split('/').pop()+'</a>':'-';h+='<tr><td>'+emEsc(r.document_type)+'</td><td>'+emEsc(r.document_category)+'</td><td>'+emEsc(r.document_title)+'</td><td>'+emEsc(r.document_number)+'</td><td>'+emEsc(r.issue_date)+'</td><td>'+emEsc(r.expiry_date)+'</td><td>'+file+'</td><td>'+emEsc((r.verification_status||'')+' / '+(r.status||''))+'</td><td><button type="button" class="btn btn-danger btn-xs btn-del-document" data-i="'+i+'"><i class="fa fa-trash"></i></button></td></tr>';});$('#tbl_document tbody').html(h||'<tr><td colspan="9" class="text-center text-muted">Belum ada document data.</td></tr>');emSyncChildJson();}
function emResetFamilyInput(){$('#fam_relationship_type').val('SPOUSE').trigger('change');$('#fam_family_name,#fam_birth_date,#fam_identity_no,#fam_phone').val('');$('#fam_gender').val('MALE').trigger('change');$('#fam_identity_type').val('KTP').trigger('change');$('#fam_is_dependent,#fam_emergency_contact').val('N').trigger('change');$('#fam_status').val('ACTIVE').trigger('change');}
function emResetEducationInput(){$('#edu_education_level').val('S1').trigger('change');$('#edu_education_type').val('FORMAL').trigger('change');$('#edu_institution_name,#edu_major,#edu_graduation_year,#edu_certificate_no,#edu_gpa,#edu_document_ref').val('');$('#edu_highest_education').val('N').trigger('change');$('#edu_verified_status').val('PENDING').trigger('change');$('#edu_status').val('ACTIVE').trigger('change');}
function emResetDocumentInput(){$('#doc_document_type').val('KTP').trigger('change');$('#doc_document_category').val('PERSONAL').trigger('change');$('#doc_document_title,#doc_document_number,#doc_issue_date,#doc_expiry_date,#doc_file_ref,#doc_file_upload').val('');$('#doc_confidential,#doc_mandatory_document').val('N').trigger('change');$('#doc_verification_status').val('PENDING').trigger('change');$('#doc_status').val('ACTIVE').trigger('change');}
function emUploadDocumentFile(cb){var input=$('#doc_file_upload')[0];if(!input||!input.files||!input.files.length){cb('');return;}var fd=new FormData();fd.append('document_file',input.files[0]);$('#btn_add_document').prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i>');$.ajax({url:'<?=base_admin();?>modul/employee_master_data/employee_master_data_action.php?act=upload_document_file',type:'POST',data:fd,processData:false,contentType:false,dataType:'json',success:function(r){$('#btn_add_document').prop('disabled',false).html('<i class="fa fa-plus"></i>');if(r.status==='good')cb(r.file_ref||'');else emError(r.error_message);},error:function(xhr){$('#btn_add_document').prop('disabled',false).html('<i class="fa fa-plus"></i>');emError(xhr.responseText||'Upload document gagal.');}});}
function emLoadNextNo(){if($('#em_id').val()!=='')return;$('#employee_no').val(<?=hr_js('common_loading', 'Loading...');?>);$.post('<?=base_admin();?>modul/employee_master_data/employee_master_data_action.php?act=next_no',{},function(r){if(r.status==='good')$('#employee_no').val(r.employee_no);else emError(r.error_message);},'json').fail(function(x){emError(x.responseText);});}
function emReset(title,autoNo){$('#form_employee')[0].reset();$('#em_id').val('');emFamilies=[];emEducations=[];emDocuments=[];emRenderChildren();emResetFamilyInput();emResetEducationInput();emResetDocumentInput();$('#department_code,#job_title_id,#company_structure_id,#manager_employee_id,#cost_center_code,#profit_center_code,#user_id').val(null).trigger('change');$('#gender,#marital_status,#religion,#identity_type,#employment_status,#employee_group,#employee_subgroup,#payroll_area,#pay_grade,#work_location_type,#shift_code').val('').trigger('change');$('#gender').val('MALE').trigger('change');$('#marital_status').val('SINGLE').trigger('change');$('#identity_type').val('KTP').trigger('change');$('#employment_status').val('ACTIVE').trigger('change');$('#employee_group').val('STAFF').trigger('change');$('#work_location_type').val('OFFICE').trigger('change');$('#nationality').val('ID');$('#hire_date').val('<?=date('Y-m-d');?>');$('#valid_from').val('<?=$defaultFrom;?>');$('#valid_to').val('<?=$defaultTo;?>');$('#modal_employee .modal-title').text(title||'Create Employee');$('#modal_employee a[href="#em_tab_profile"]').tab('show');if(autoNo)emLoadNextNo();}
function emAjax(selector,act,placeholder){$(selector).select2({width:'100%',allowClear:true,placeholder:placeholder,dropdownParent:$('#modal_employee'),ajax:{url:'<?=base_admin();?>modul/employee_master_data/employee_master_data_action.php?act='+act,type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||'',exclude:$('#em_id').val(),department_code:$('#department_code').val()||''};},processResults:function(d){return{results:d.results||[]};}}});}
$(function(){if($.fn.datepicker){$('.em-date,.date-field').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_employment_status,#filter_employee_group').select2({width:'100%',allowClear:true});$('#gender,#marital_status,#religion,#identity_type,#employment_status,#employee_group,#employee_subgroup,#payroll_area,#pay_grade,#work_location_type,#shift_code,.child-select').select2({width:'100%',allowClear:true,dropdownParent:$('#modal_employee')});$('#filter_department_code').select2({width:'100%',allowClear:true,placeholder:'Semua Department',ajax:{url:'<?=base_admin();?>modul/employee_master_data/employee_master_data_action.php?act=department_search',type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||''};},processResults:function(d){return{results:d.results||[]};}}});emAjax('#department_code','department_search','Pilih Department...');emAjax('#job_title_id','job_title_search','Pilih Job Title...');emAjax('#company_structure_id','company_structure_search','Pilih Org Unit...');emAjax('#manager_employee_id','employee_search','Pilih Manager...');emAjax('#cost_center_code','cost_center_search','Pilih Cost Center...');emAjax('#profit_center_code','profit_center_search','Pilih Profit Center...');emAjax('#user_id','user_search','Pilih User Account...');}
var dt=$('#dtb_employee_master').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'42px',targets:0},{width:'135px',targets:1}],ajax:{url:'<?=base_admin();?>modul/employee_master_data/employee_master_data_data.php',type:'post',data:function(d){$.extend(d,emFilters());},dataSrc:function(json){var k=json.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_active').text(k.active||0);$('#kpi_operators').text(k.operators||0);$('#kpi_leaders').text(k.leaders||0);return json.data||[];},error:function(xhr){console.log(xhr.responseText);emError('Data Employee gagal dimuat.');}}});
$('#btn_open_em').click(function(){emReset('Create Employee',true);$('#modal_employee').modal({backdrop:'static',keyboard:false});});$('#btn_reload_employee_no').click(function(){emLoadNextNo();});$('#btn_filter_em').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_em').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_employment_status,#filter_employee_group,#filter_department_code').val(null).trigger('change');$('#filter_keyword').val('');dt.draw();});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});$('#employee_no,#nationality').on('keyup change',function(){this.value=this.value.toUpperCase();});
$('#btn_add_family').click(function(){var name=$.trim($('#fam_family_name').val());if(!name){emError('Family Name wajib diisi.');return;}emFamilies.push({relationship_type:$('#fam_relationship_type').val(),family_name:name,gender:$('#fam_gender').val(),birth_date:$('#fam_birth_date').val(),identity_type:$('#fam_identity_type').val(),identity_no:$('#fam_identity_no').val(),phone:$('#fam_phone').val(),is_dependent:$('#fam_is_dependent').val(),emergency_contact:$('#fam_emergency_contact').val(),status:$('#fam_status').val()});emResetFamilyInput();emRenderChildren();});
$('#btn_add_education').click(function(){var inst=$.trim($('#edu_institution_name').val());if(!inst){emError('Institution wajib diisi.');return;}if($('#edu_highest_education').val()==='Y'){emEducations.forEach(function(r){r.highest_education='N';});}emEducations.push({education_level:$('#edu_education_level').val(),education_type:$('#edu_education_type').val(),institution_name:inst,major:$('#edu_major').val(),graduation_year:$('#edu_graduation_year').val(),certificate_no:$('#edu_certificate_no').val(),gpa:$('#edu_gpa').val(),highest_education:$('#edu_highest_education').val(),verified_status:$('#edu_verified_status').val(),document_ref:$('#edu_document_ref').val(),status:$('#edu_status').val()});emResetEducationInput();emRenderChildren();});
$('#btn_add_document').click(function(){var title=$.trim($('#doc_document_title').val());if(!title){emError('Document Title wajib diisi.');return;}emUploadDocumentFile(function(fileRef){emDocuments.push({document_type:$('#doc_document_type').val(),document_category:$('#doc_document_category').val(),document_title:title,document_number:$('#doc_document_number').val(),issue_date:$('#doc_issue_date').val(),expiry_date:$('#doc_expiry_date').val(),file_ref:fileRef,confidential:$('#doc_confidential').val(),mandatory_document:$('#doc_mandatory_document').val(),verification_status:$('#doc_verification_status').val(),status:$('#doc_status').val()});emResetDocumentInput();emRenderChildren();});});
$(document).on('click','.btn-del-family',function(){emFamilies.splice($(this).data('i'),1);emRenderChildren();});$(document).on('click','.btn-del-education',function(){emEducations.splice($(this).data('i'),1);emRenderChildren();});$(document).on('click','.btn-del-document',function(){emDocuments.splice($(this).data('i'),1);emRenderChildren();});
$('#form_employee').submit(function(e){e.preventDefault();emSyncChildJson();var btn=$(this).find('button[type=submit]');btn.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> <?=hr_h('common_saving', 'Saving...');?>');$.post('<?=base_admin();?>modul/employee_master_data/employee_master_data_action.php?act=save',$(this).serialize(),function(r){btn.prop('disabled',false).html('<i class="fa fa-save"></i> Save Employee');if(r.status==='good'){$('#modal_employee').modal('hide');dt.draw(false);Swal.fire('Saved','Employee berhasil disimpan.','success');}else emError(r.error_message);},'json').fail(function(xhr){btn.prop('disabled',false).html('<i class="fa fa-save"></i> Save Employee');emError(xhr.responseText);});});
$(document).on('click','.btn-em-detail',function(){$.post('<?=base_admin();?>modul/employee_master_data/employee_master_data_action.php?act=detail',{id:$(this).data('id')},function(html){$('#em_detail_body').html(html);$('#modal_em_detail').modal('show');});});
$(document).on('click','.btn-em-edit',function(){var id=$(this).data('id');$.post('<?=base_admin();?>modul/employee_master_data/employee_master_data_action.php?act=get',{id:id},function(r){if(r.status!=='good'){emError(r.error_message);return;}emReset('Edit Employee',false);var h=r.data||{};Object.keys(h).forEach(function(k){var el=$('#'+k);if(el.length&&!['department_code','job_title_id','company_structure_id','manager_employee_id','cost_center_code','profit_center_code','user_id'].includes(k))el.val(h[k]);});$('#em_id').val(h.id);emFamilies=h.families||[];emEducations=h.educations||[];emDocuments=h.documents||[];emRenderChildren();emSet('#department_code',h.department_code,h.department_text);emSet('#job_title_id',h.job_title_id,h.job_title_text);emSet('#company_structure_id',h.company_structure_id,h.company_structure_text);emSet('#manager_employee_id',h.manager_employee_id,h.manager_text);emSet('#cost_center_code',h.cost_center_code,h.cost_center_text);emSet('#profit_center_code',h.profit_center_code,h.profit_center_text);emSet('#user_id',h.user_id,h.user_text);$('#gender,#marital_status,#religion,#identity_type,#employment_status,#employee_group,#employee_subgroup,#payroll_area,#pay_grade,#work_location_type,#shift_code').trigger('change');$('#modal_employee').modal({backdrop:'static',keyboard:false});},'json');});
$(document).on('click','.btn-em-delete',function(){var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:erpLang('confirm_delete_title','Delete Confirmation'),text:no,icon:'warning',showCancelButton:true,confirmButtonText:erpLang('common_delete','Delete'),cancelButtonText:erpLang('common_cancel','Cancel')}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/employee_master_data/employee_master_data_action.php?act=delete',{id:id},function(r){if(r.status==='good'){dt.draw(false);Swal.fire(erpLang('common_deleted','Deleted'),erpLang('common_deleted_message','Data deleted successfully.'),'success');}else emError(r.error_message);},'json');});});});
</script>
